const express = require('express');
const { body, validationResult } = require('express-validator');
const app = express();
app.use(express.json());

let products = [];
let nextId = 1;

// Custom error class
class AppError extends Error {
  constructor(message, statusCode) {
    super(message);
    this.statusCode = statusCode;
  }
}

// Validation rules
const productValidation = [
  body('name').notEmpty().withMessage('Name is required').isString(),
  body('price').isFloat({ gt: 0 }).withMessage('Price must be a positive number'),
  body('category').notEmpty().withMessage('Category is required').isString()
];

// GET all
app.get('/products', (req, res) => {
  res.json(products);
});

// GET one
app.get('/products/:id', (req, res, next) => {
  const id = parseInt(req.params.id);
  const product = products.find(p => p.id === id);
  if (!product) return next(new AppError('Product not found', 404));
  res.json(product);
});

// POST with validation
app.post('/products', productValidation, (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return next(new AppError(errors.array()[0].msg, 400));
  }
  const { name, price, category } = req.body;
  const newProduct = { id: nextId++, name, price, category };
  products.push(newProduct);
  res.status(201).json(newProduct);
});

// PUT (full update) – reuse validation
app.put('/products/:id', productValidation, (req, res, next) => {
  const id = parseInt(req.params.id);
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return next(new AppError(errors.array()[0].msg, 400));
  }
  const product = products.find(p => p.id === id);
  if (!product) return next(new AppError('Product not found', 404));
  const { name, price, category } = req.body;
  product.name = name;
  product.price = price;
  product.category = category;
  res.json(product);
});

// PATCH – allow partial updates, but validate if present
app.patch('/products/:id', (req, res, next) => {
  const id = parseInt(req.params.id);
  const updates = req.body;
  const product = products.find(p => p.id === id);
  if (!product) return next(new AppError('Product not found', 404));
  // simple validation
  if (updates.name !== undefined && typeof updates.name !== 'string') {
    return next(new AppError('Name must be a string', 400));
  }
  if (updates.price !== undefined && (typeof updates.price !== 'number' || updates.price <= 0)) {
    return next(new AppError('Price must be a positive number', 400));
  }
  if (updates.category !== undefined && typeof updates.category !== 'string') {
    return next(new AppError('Category must be a string', 400));
  }
  Object.assign(product, updates);
  res.json(product);
});

// DELETE
app.delete('/products/:id', (req, res, next) => {
  const id = parseInt(req.params.id);
  const index = products.findIndex(p => p.id === id);
  if (index === -1) return next(new AppError('Product not found', 404));
  products.splice(index, 1);
  res.status(204).send();
});

// 404 handler for unmatched routes
app.use((req, res, next) => {
  next(new AppError('Route not found', 404));
});

// Central error handler
app.use((err, req, res, next) => {
  const status = err.statusCode || 500;
  res.status(status).json({
    error: {
      message: err.message || 'Internal Server Error',
      status
    }
  });
});

app.listen(3000);
